SELECT COUNT(da.dataset_id) AS number_of_datasets_accessed
FROM dataset_access da
WHERE da.user_id = 0;

SELECT COUNT(*) AS active_aeromagnetic_count, AVG(version) AS average_version
FROM datasets
WHERE type = 'Aeromagnetic' AND status = 'active';

SELECT users.user_name, user_roles.role_name
FROM users
JOIN user_roles ON users.role = user_roles.role_id;

SELECT COUNT(dataset_id) AS dataset_count
FROM dataset_access
WHERE user_id = 1;

SELECT title 
FROM datasets 
WHERE dataset_id IN (SELECT dataset_id FROM dataset_access);

SELECT title
FROM datasets
WHERE dataset_id = 0;
